import pathlib

total = 0
for py_file in pathlib.Path('.').rglob('*.py'):
    try:
        with open(py_file, 'r', encoding='utf-8') as f:
            total += sum(1 for _ in f)
    except (UnicodeDecodeError, OSError):
        continue

with open('total.txt', 'w', encoding='utf-8') as out:
    out.write(f'{total}\n')

